from collections import deque

def diagonal_moves(q, queries):
    max_diagonal_moves = 0
    for query in queries:
        n, m, k = query
        if n == 0 and m == 0:
            return -1
        elif n == 0 or m == 0:
            continue
        elif k == 0:
            return max_diagonal_moves
        else:
            d = deque()
            while len(d) < k:
                d.append(n)
                if d[0] == m:
                    break
            else:
                moves = [(i, j) for i in range(min(n, m), max(n, m)) for j in range(min(n, m), max(n, m))]
                max_diagonal_moves = max(max_diagonal_moves, len(moves))
    return max_diagonal_moves

